import React, { FC, useEffect, useMemo, useRef, useState } from "react";
import ReactDOM from "react-dom";

import { useSavedReducer } from "../../../hooks";
import { UiContext } from "../../../contexts/ui";
import { Icon, RemoveIcon } from "../../../views/shared";
import {
  addTodo,
  removeTodo,
  toggleTodo,
  dismissTodo,
  updateTodo,
  updateTodoMeta,
  completeRepeatInstance,
  uncompleteRepeatInstance,
  moveTodo,
} from "../todo/actions";
import { nanoid } from "nanoid";
import { reducer, Repeat, State } from "../todo/reducer";
import { defaultData, Props, CustomList } from "../todo/types";
import { calculateCappedHeights } from "../../../hooks/calculateCappedHeights";
import "./TodoPlus.sass";

const dayLabels = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

const getYmd = (date: Date) =>
  `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}-${String(
    date.getDate(),
  ).padStart(2, "0")}`;

const parseDate = (value?: string) => {
  if (!value) return null;
  const parsed = new Date(`${value}T00:00:00`);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
};

const addDays = (date: Date, days: number) =>
  new Date(date.getFullYear(), date.getMonth(), date.getDate() + days);

const nextRepeatDate = (
  repeat: Repeat,
  dueDate: string | undefined,
  today: Date,
): Date | null => {
  const base = parseDate(dueDate) ?? today;
  if (repeat.type === "daily") return addDays(base, 1);

  const selectedDays =
    repeat.type === "custom"
      ? repeat.days
      : repeat.days && repeat.days.length
        ? repeat.days
        : [base.getDay()];

  if (!selectedDays.length) return null;
  for (let offset = 1; offset <= 7; offset += 1) {
    const candidate = addDays(base, offset);
    if (selectedDays.includes(candidate.getDay())) return candidate;
  }
  return null;
};

const firstRepeatDate = (repeat: Repeat, today: Date): Date | null => {
  if (repeat.type === "daily") return today;
  const selectedDays =
    repeat.type === "custom"
      ? repeat.days
      : repeat.days && repeat.days.length
        ? repeat.days
        : [today.getDay()];
  if (!selectedDays.length) return null;
  for (let offset = 0; offset <= 6; offset += 1) {
    const candidate = addDays(today, offset);
    if (selectedDays.includes(candidate.getDay())) return candidate;
  }
  return null;
};

const TodoPlus: FC<Props> = ({ data = defaultData, setData }) => {
  const { toggleSettings } = React.useContext(UiContext);
  const rootRef = useRef<HTMLDivElement | null>(null);
  const duePanelRef = useRef<HTMLDivElement | null>(null);
  const dueListRef = useRef<HTMLDivElement | null>(null);
  const remainingPanelRef = useRef<HTMLDivElement | null>(null);
  const remainingListRef = useRef<HTMLDivElement | null>(null);

  const [input, setInput] = useState("");
  const [inputFocused, setInputFocused] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [remainingMenuOpen, setRemainingMenuOpen] = useState(false);
  const [dueListMenuOpen, setDueListMenuOpen] = useState(false);
  const [dueViewMenuOpen, setDueViewMenuOpen] = useState(false);
  const [dueView, setDueView] = useState<"today" | "finished" | string>("today");
  const [completeMenuId, setCompleteMenuId] = useState<string | null>(null);
  const [itemMenuId, setItemMenuId] = useState<string | null>(null);
  const [popoverAnchor, setPopoverAnchor] = useState<{ top: number; left: number; right: number; bottom: number } | null>(null);
  const [completeMenuAnchor, setCompleteMenuAnchor] = useState<{ top: number; left: number; right: number; bottom: number } | null>(null);
  const [draftItemMeta, setDraftItemMeta] = useState<{
    id: string;
    dueDate?: string;
    repeat?: Repeat;
  } | null>(null);
  const [dueDate, setDueDate] = useState<string | undefined>(undefined);
  const [repeatType, setRepeatType] = useState<
    "none" | "daily" | "weekly" | "custom"
  >("none");
  const [customDays, setCustomDays] = useState<number[]>([]);
  const [dueOpen, setDueOpen] = useState(true);
  const [remainingOpen, setRemainingOpen] = useState(true);
  const [listCaps, setListCaps] = useState<Record<string, number>>({ due: 220, remaining: 220 });
  const [cappedLists, setCappedLists] = useState<Record<string, boolean>>({ due: false, remaining: false });
  const activeListRef = useRef(1); // 0 = due panel, 1 = inbox panel

  const customLists = data?.customLists ?? [];
  const [selectedListId, setSelectedListId] = useState<string | undefined>(undefined);
  const [listPickerOpen, setListPickerOpen] = useState(false);
  const [addingListPanel, setAddingListPanel] = useState<"due" | "inbox" | null>(null);
  const [newListName, setNewListName] = useState("");
  const [renamingListId, setRenamingListId] = useState<string | null>(null);
  const [renameValue, setRenameValue] = useState("");
  const [inboxViewMenuOpen, setInboxViewMenuOpen] = useState(false);
  const [inboxView, setInboxView] = useState<"inbox" | string>("inbox");

  const repeatEqual = (a?: Repeat, b?: Repeat) => {
    if (!a && !b) return true;
    if (!a || !b) return false;
    if (a.type !== b.type) return false;
    if (a.type === "custom" && b.type === "custom") {
      const aDays = [...(a.days ?? [])].sort();
      const bDays = [...(b.days ?? [])].sort();
      return aDays.length === bDays.length && aDays.every((d, i) => d === bDays[i]);
    }
    return true;
  };

  const normalizeRepeat = (repeat?: Repeat): Repeat | undefined => {
    if (!repeat) return undefined;
    if (repeat.type === "custom" && (!repeat.days || repeat.days.length === 0)) return undefined;
    return repeat;
  };

  const commitDraftItemMeta = () => {
    if (!draftItemMeta) return;
    const current = itemById.get(draftItemMeta.id);
    if (!current) {
      setDraftItemMeta(null);
      return;
    }
    const finalRepeat = normalizeRepeat(draftItemMeta.repeat);
    if (
      current.dueDate !== draftItemMeta.dueDate ||
      !repeatEqual(current.repeat, finalRepeat)
    ) {
      dispatch(
        updateTodoMeta(draftItemMeta.id, {
          dueDate: draftItemMeta.dueDate,
          repeat: finalRepeat,
        }),
      );
    }
    setDraftItemMeta(null);
  };

  const closeAllMenus = () => {
    commitDraftItemMeta();
    if (menuOpen && input.trim()) {
      submitCurrentTask();
    }
    setMenuOpen(false);
    setRemainingMenuOpen(false);
    setDueListMenuOpen(false);
    setDueViewMenuOpen(false);
    setInboxViewMenuOpen(false);
    setCompleteMenuId(null);
    setCompleteMenuAnchor(null);
    setItemMenuId(null);
    setPopoverAnchor(null);
    setListPickerOpen(false);
    if (addingListPanel && newListName.trim()) {
      commitAddList();
    }
    setAddingListPanel(null);
    setNewListName("");
    if (renamingListId && renameValue.trim()) {
      commitRename();
    }
    setRenamingListId(null);
    setRenameValue("");
  };

  const closeAllMenusRef = useRef(closeAllMenus);
  closeAllMenusRef.current = closeAllMenus;

  useEffect(() => {
    const handleClick = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      if (
        target.closest(".list-menu") ||
        target.closest(".menu") ||
        target.closest(".item-popover") ||
        target.closest(".section-menu") ||
        target.closest(".item-menu") ||
        target.closest(".menu-toggle") ||
        target.closest(".due-view-menu") ||
        target.closest(".inbox-view-menu") ||
        target.closest(".complete-menu") ||
        target.closest(".list-picker") ||
        target.closest(".inline-add-list") ||
        target.closest(".inline-rename")
      ) {
        return;
      }
      closeAllMenusRef.current();
    };
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  const setItems = (items: State) => setData({ ...data, items });
  const [items, dispatch] = useSavedReducer(reducer, data.items, setItems);
  const today = new Date();
  const todayYmd = getYmd(today);
  const todayDay = today.getDay();

  // Latest items/data refs so the daily-clear effect doesn't read stale values
  const itemsRef = useRef(items);
  itemsRef.current = items;
  const dataRef = useRef(data);
  dataRef.current = data;

  // Auto-dismiss completed items from the "due today" list at the start of each new day.
  // The lastClearedDate write is deferred to a setTimeout so it fires AFTER the reducer's
  // items-save effect has propagated through setData; otherwise the two setData calls
  // (which both spread `data` whole) race and the later one drops the dismissed items.
  useEffect(() => {
    if (dataRef.current.lastClearedDate === todayYmd) return;
    const toClear = itemsRef.current.filter(
      (item) =>
        !item.dismissed &&
        item.completed &&
        item.dueDate &&
        item.dueDate < todayYmd,
    );
    if (toClear.length === 0) {
      setData({ ...dataRef.current, lastClearedDate: todayYmd });
      return;
    }
    toClear.forEach((item) => dispatch(dismissTodo(item.id)));
    const handle = setTimeout(() => {
      setData({ ...dataRef.current, lastClearedDate: todayYmd });
    }, 0);
    return () => clearTimeout(handle);
  }, [todayYmd]);

  const repeat: Repeat | undefined = useMemo(() => {
    if (repeatType === "daily") return { type: "daily" };
    if (repeatType === "weekly") {
      return customDays.length ? { type: "weekly", days: customDays } : { type: "weekly" };
    }
    if (repeatType === "custom") {
      const days = [...customDays].sort((a, b) => a - b);
      return days.length > 0 ? { type: "custom", days } : undefined;
    }
    return undefined;
  }, [repeatType, customDays]);

  function submitCurrentTask() {
    const trimmed = input.trim();
    if (!trimmed) return;
    activeListRef.current = dueDate === todayYmd ? 0 : 1;
    dispatch(addTodo(trimmed, { dueDate, repeat, listId: selectedListId }));
    setInput("");
    setDueDate(undefined);
    setRepeatType("none");
    setCustomDays([]);
  }

  const submitTaskWithMeta = (meta?: { dueDate?: string; repeat?: Repeat }) => {
    const trimmed = input.trim();
    if (!trimmed) return false;
    const finalDueDate = meta?.dueDate ?? dueDate;
    activeListRef.current = finalDueDate === todayYmd ? 0 : 1;
    dispatch(
      addTodo(trimmed, {
        dueDate: finalDueDate,
        repeat: meta?.repeat ?? repeat,
        listId: selectedListId,
      }),
    );
    setInput("");
    setDueDate(undefined);
    setRepeatType("none");
    setCustomDays([]);
    return true;
  };

  const handleAdd = () => {
    submitTaskWithMeta();
    closeAllMenus();
  };

  const handleAddWithDueDate = (date: string) => {
    const trimmed = input.trim();
    if (!trimmed) {
      setDueDate(date);
      return;
    }
    submitTaskWithMeta({ dueDate: date });
    closeAllMenus();
  };

  const showMenuToggle = inputFocused || input.trim().length > 0;

  // ── List CRUD helpers ─────────────────────────────────────
  const commitAddList = () => {
    const trimmed = newListName.trim();
    if (!trimmed) return;
    const newList: CustomList = { id: nanoid(), name: trimmed };
    setData({ ...data, customLists: [...customLists, newList] });
    // Switch the panel that initiated the add to show the new list
    if (addingListPanel === "due") setDueView(newList.id);
    else if (addingListPanel === "inbox") setInboxView(newList.id);
    setNewListName("");
    setAddingListPanel(null);
  };

  const commitRename = () => {
    if (!renamingListId) return;
    const trimmed = renameValue.trim();
    if (!trimmed) { setRenamingListId(null); return; }
    setData({
      ...data,
      customLists: customLists.map((l) =>
        l.id === renamingListId ? { ...l, name: trimmed } : l,
      ),
    });
    setRenamingListId(null);
    setRenameValue("");
  };

  const deleteList = (listId: string) => {
    // Move all tasks in the deleted list back to inbox
    const affected = items.filter((item) => item.listId === listId);
    affected.forEach((item) => dispatch(moveTodo(item.id, undefined)));
    // Defer the customLists update so it fires after the reducer's items-save
    // setData has propagated; otherwise it would race and clobber the moveTodo
    // results (both setData calls spread `data` whole and the later one wins).
    const writeLists = () => {
      setData({
        ...dataRef.current,
        customLists: (dataRef.current.customLists ?? []).filter(
          (l) => l.id !== listId,
        ),
      });
    };
    if (affected.length === 0) {
      writeLists();
    } else {
      setTimeout(writeLists, 0);
    }
    // Reset views/selection if they were pointing at the deleted list
    if (dueView === listId) setDueView("today");
    if (inboxView === listId) setInboxView("inbox");
    if (selectedListId === listId) setSelectedListId(undefined);
  };

  const startAddList = (panel: "due" | "inbox") => {
    closeAllMenus();
    setNewListName("");
    setAddingListPanel(panel);
  };

  const startRenameList = (list: CustomList) => {
    closeAllMenus();
    setRenameValue(list.name);
    setRenamingListId(list.id);
  };
  // ──────────────────────────────────────────────────────────

  const formatDueDate = (date?: string) => {
    if (!date) return null;
    const parsed = parseDate(date);
    if (!parsed || Number.isNaN(parsed.getTime())) return date;
    return parsed.toLocaleDateString(undefined, {
      month: "short",
      day: "numeric",
    });
  };

  const formatRepeat = (value?: Repeat) => {
    if (!value) return null;
    if (value.type === "daily") return "Daily";
    if (value.type === "weekly") return "Weekly";
    if (value.type === "custom") {
      const days =
        value.days?.length > 0
          ? value.days.map((day) => dayLabels[day]).join(", ")
          : "";
      return days ? days : "Custom";
    }
    return null;
  };

  const getRepeatDerivedDueDate = (repeat?: Repeat) => {
    if (!repeat) return undefined;
    const firstDate = firstRepeatDate(repeat, today);
    return firstDate ? getYmd(firstDate) : undefined;
  };

  const getTaskDisplayDueDate = (item: State[number]) =>
    item.dueDate ?? (item.repeat ? getRepeatDerivedDueDate(item.repeat) : undefined);

  const getRepeatDays = (item: State[number]) => {
    if (!item.repeat) return null;
    if (item.repeat.type === "daily") return [0, 1, 2, 3, 4, 5, 6];
    if (item.repeat.type === "custom") return item.repeat.days ?? [];
    if (item.repeat.type === "weekly") {
      if (item.repeat.days && item.repeat.days.length) return item.repeat.days;
      const parsed = parseDate(item.dueDate);
      return parsed ? [parsed.getDay()] : [];
    }
    return null;
  };

  const isOverdue = (item: State[number]) => {
    if (!item.dueDate || item.completed) return false;
    return item.dueDate < todayYmd;
  };

  const isDueToday = (item: State[number]) => {
    if (item.dueDate && item.dueDate === todayYmd) return true;

    // Overdue items (due date before today) should appear in the due today list
    if (item.dueDate && item.dueDate < todayYmd) return true;

    const repeatDays = getRepeatDays(item);
    if (!repeatDays) return false;

    if (item.dueDate) {
      const start = parseDate(item.dueDate);
      if (start && start > today) return false;
    }

    return repeatDays.includes(todayDay);
  };

  const activeItems = items.filter((item) => !item.dismissed);
  const finished = items.filter((item) => item.dismissed);

  // Determine effective list membership (invalid listIds fall back to inbox)
  const customListIds = useMemo(() => new Set(customLists.map((l) => l.id)), [customLists]);
  const getEffectiveListId = (item: State[number]) =>
    item.listId && customListIds.has(item.listId) ? item.listId : undefined;

  // Items not assigned to any custom list
  const unlistedActive = activeItems.filter((item) => !getEffectiveListId(item));
  const dueToday = [...unlistedActive.filter((item) => isDueToday(item))].sort((a, b) => {
    if (a.completed !== b.completed) return a.completed ? 1 : -1;
    return 0;
  });
  const remaining = unlistedActive.filter((item) => !isDueToday(item));
  const remainingSorted = [...remaining].sort((a, b) => {
    if (a.completed !== b.completed) return a.completed ? 1 : -1;
    const aDue = getTaskDisplayDueDate(a);
    const bDue = getTaskDisplayDueDate(b);
    if (!aDue && !bDue) return 0;
    if (!aDue) return -1;
    if (!bDue) return 1;
    return aDue.localeCompare(bDue);
  });
  const finishedSorted = [...finished].sort((a, b) => {
    const aDue = getTaskDisplayDueDate(a);
    const bDue = getTaskDisplayDueDate(b);
    if (!aDue && !bDue) return 0;
    if (!aDue) return -1;
    if (!bDue) return 1;
    return aDue.localeCompare(bDue);
  });

  // Items in custom lists (active, not dismissed)
  const customListItemsMap: Record<string, State> = {};
  customLists.forEach((cl) => {
    const clItems = activeItems.filter((item) => getEffectiveListId(item) === cl.id);
    customListItemsMap[cl.id] = [...clItems].sort((a, b) => {
      if (a.completed !== b.completed) return a.completed ? 1 : -1;
      const aDue = getTaskDisplayDueDate(a);
      const bDue = getTaskDisplayDueDate(b);
      if (!aDue && !bDue) return 0;
      if (!aDue) return -1;
      if (!bDue) return 1;
      return aDue.localeCompare(bDue);
    });
  });

  const dueList = dueView === "today"
    ? dueToday
    : dueView === "finished"
      ? finishedSorted
      : customListItemsMap[dueView] ?? [];
  const dueLabel = dueView === "today"
    ? "Due Today"
    : dueView === "finished"
      ? "Finished Tasks"
      : customLists.find((l) => l.id === dueView)?.name ?? "Unknown List";

  const inboxList = inboxView === "inbox"
    ? remainingSorted
    : customListItemsMap[inboxView] ?? [];
  const inboxLabel = inboxView === "inbox"
    ? "Inbox"
    : customLists.find((l) => l.id === inboxView)?.name ?? "Unknown List";

  // In the Finished view every item is dismissed (and "finished" is what the user
  // sees), so remove the dismissed ones. Elsewhere "Remove Finished Items" means
  // the completed ones in that view.
  const removeCompleted = (list: State, finishedView = false) => {
    const predicate = finishedView
      ? (item: State[number]) => item.dismissed
      : (item: State[number]) => item.completed;
    list.filter(predicate).forEach((item) => {
      dispatch(removeTodo(item.id));
    });
  };

  const itemById = useMemo(
    () => new Map(items.map((item) => [item.id, item])),
    [items],
  );

  const renderRepeatMenu = (
    currentRepeat: Repeat | undefined,
    onRepeatChange: (next?: Repeat) => void,
    currentDueDate?: string,
    onDueDateChange?: (next?: string) => void,
    onClose?: (next?: { dueDate?: string; repeat?: Repeat }) => void,
  ) => (
    <div className="menu">
      <div className="menu-row">
        <div className="menu-row-label">
          <span>Due date</span>
          {(currentDueDate || getRepeatDerivedDueDate(currentRepeat)) && (
            <span className="menu-row-value">
              {formatDueDate(currentDueDate ?? getRepeatDerivedDueDate(currentRepeat))}
            </span>
          )}
        </div>
        <label className="calendar-button">
          <Icon name="calendar" />
          <input
            type="date"
            value={currentDueDate ?? ""}
            onChange={(event) => {
              const nextDueDate = event.target.value || undefined;
              onDueDateChange?.(nextDueDate);
              onClose?.({ dueDate: nextDueDate, repeat: currentRepeat });
            }}
          />
        </label>
      </div>

      <div className="repeat">
        <span>Repeat</span>
        <div className="repeat-options">
          {(["none", "daily", "weekly", "custom"] as const).map((option) => (
            <button
              key={option}
              className={
                (currentRepeat?.type ?? "none") === option ? "active" : ""
              }
              onClick={() => {
                const nextRepeat: Repeat | undefined =
                  option === "none"
                    ? undefined
                    : option === "daily"
                      ? { type: "daily" }
                      : option === "weekly"
                        ? {
                            type: "weekly",
                            days:
                              currentRepeat?.type === "weekly"
                                ? currentRepeat.days
                                : currentRepeat?.type === "custom"
                                  ? currentRepeat.days
                                  : [todayDay],
                          }
                        : {
                            type: "custom",
                            days:
                              currentRepeat?.type === "custom"
                                ? currentRepeat.days
                                : [],
                          };
                onRepeatChange(nextRepeat);
                if (
                  option === "custom" &&
                  !currentDueDate &&
                  nextRepeat &&
                  nextRepeat.type === "custom"
                ) {
                  // Repeat-derived due date is displayed independently from manual dueDate.
                }
                if (option === "daily" || option === "none") {
                  onClose?.({ dueDate: currentDueDate, repeat: nextRepeat });
                }
              }}
            >
              {option === "none"
                ? "None"
                : option === "daily"
                  ? "Daily"
                  : option === "weekly"
                    ? "Weekly"
                    : "Custom"}
            </button>
          ))}
        </div>

        {((currentRepeat?.type ?? "none") === "custom" ||
          (currentRepeat?.type ?? "none") === "weekly") && (
          <div className="custom-days">
            {dayLabels.map((label, index) => {
              const isWeekly = (currentRepeat?.type ?? "none") === "weekly";
              const days =
                currentRepeat?.type === "custom"
                  ? currentRepeat.days
                  : currentRepeat?.type === "weekly"
                    ? currentRepeat.days ?? []
                    : [];
              const active = days.includes(index);
              return (
                <button
                  key={label}
                  className={active ? "active" : ""}
                  onClick={() => {
                    if (isWeekly) {
                      const nextRepeat: Repeat = { type: "weekly", days: [index] };
                      onRepeatChange(nextRepeat);
                      onClose?.({ dueDate: currentDueDate, repeat: nextRepeat });
                      return;
                    }
                    onRepeatChange({
                      type: "custom",
                      days: active
                        ? days.filter((d: number) => d !== index)
                        : days.concat(index),
                    });
                  }}
                >
                  {label}
                </button>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );

  const renderItems = (
    list: State,
    listIdx: number,
    options: { showDue: boolean; showRepeat: boolean } = {
      showDue: true,
      showRepeat: true,
    },
  ) =>
    list.map((item, index) => {
      const isDrafting = draftItemMeta?.id === item.id;
      const displayRepeat = isDrafting ? normalizeRepeat(draftItemMeta.repeat) : item.repeat;
      const displayDueDate = isDrafting
        ? (draftItemMeta.dueDate ?? (displayRepeat ? getRepeatDerivedDueDate(displayRepeat) : undefined))
        : getTaskDisplayDueDate(item);
      return (
        <div
          key={item.id}
          className={`item${item.completed ? " completed" : ""}${isOverdue(item) ? " overdue" : ""}`}
        >
        <button
          className="check"
          aria-label="Toggle task"
          onClick={(e) => {
            activeListRef.current = listIdx;
            if (item.completed) {
              if (item.parentId) {
                dispatch(uncompleteRepeatInstance(item.id, item.parentId, item.dueDate));
              } else {
                dispatch(toggleTodo(item.id));
              }
              return;
            }
            if (item.repeat) {
              closeAllMenus();
              const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
              setCompleteMenuAnchor({ top: rect.top, left: rect.left, right: rect.right, bottom: rect.bottom });
              setCompleteMenuId((prev) => (prev === item.id ? null : item.id));
              return;
            }
            dispatch(toggleTodo(item.id));
          }}
        >
          {item.completed ? <Icon name="check" size={14} /> : null}
        </button>

        <div className="content">
          <div className="content-row">
            <span
              className="text"
              contentEditable={true}
              suppressContentEditableWarning={true}
              onBlur={(event) =>
                dispatch(updateTodo(item.id, event.currentTarget.innerText))
              }
              onKeyDown={(event) => {
                if (event.key === "Enter") {
                  event.preventDefault();
                  (event.currentTarget as HTMLElement).blur();
                }
                if (event.key === "Escape") {
                  event.preventDefault();
                  event.currentTarget.innerText = item.contents;
                  (event.currentTarget as HTMLElement).blur();
                }
              }}
            >
              {item.contents}
            </span>
            {item.completed && (
              <span
                className="completed-icon"
                onClick={() => {
                  activeListRef.current = listIdx;
                  dispatch(dismissTodo(item.id));
                }}
                style={{ cursor: "pointer" }}
                title="Send to finished"
              >
                <Icon name="x" size={12} />
              </span>
            )}

            {((options.showDue && displayDueDate) ||
              (options.showRepeat && displayRepeat)) && (
              <div className="meta inline">
                {options.showDue && displayDueDate && (
                  <span>{formatDueDate(displayDueDate)}</span>
                )}
                {options.showRepeat && displayRepeat && (
                  <span>{formatRepeat(displayRepeat)}</span>
                )}
              </div>
            )}
          </div>
        </div>

        <button
          className="item-menu"
          aria-label="Task options"
          onClick={(e) => {
            closeAllMenus();
            setDraftItemMeta({
              id: item.id,
              dueDate: item.dueDate,
              repeat: item.repeat,
            });
            const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
            setPopoverAnchor({ top: rect.top, left: rect.left, right: rect.right, bottom: rect.bottom });
            setItemMenuId((prev) => (prev === item.id ? null : item.id));
          }}
        >
          <Icon name="more-horizontal" />
        </button>

        {itemMenuId === item.id && popoverAnchor && (() => {
          // Max height of the repeat menu fully expanded (due row + repeat options + custom days + padding/gaps)
          const estimatedMenuHeight = 200;
          const spaceBelow = window.innerHeight - popoverAnchor.bottom - 8;
          const popoverUp = spaceBelow < estimatedMenuHeight && popoverAnchor.top > spaceBelow;
          return ReactDOM.createPortal(
          <div
            className={`TodoPlus-portal item-popover${popoverUp ? " up" : " down"}`}
            style={popoverUp
              ? { position: "fixed", bottom: `${window.innerHeight - popoverAnchor.top + 8}px`, right: `${window.innerWidth - popoverAnchor.right}px` }
              : { position: "fixed", top: `${popoverAnchor.bottom + 8}px`, right: `${window.innerWidth - popoverAnchor.right}px` }
            }
          >
            {renderRepeatMenu(
              draftItemMeta?.repeat ?? item.repeat,
              (next) =>
                setDraftItemMeta((prev) => ({
                  id: item.id,
                  dueDate:
                    prev && prev.id === item.id
                      ? prev.dueDate
                      : item.dueDate,
                  repeat: next,
                })),
              draftItemMeta?.id === item.id
                ? draftItemMeta?.dueDate
                : item.dueDate,
              (next) =>
                setDraftItemMeta((prev) => ({
                  id: item.id,
                  dueDate: next,
                  repeat:
                    prev && prev.id === item.id
                      ? prev.repeat
                      : item.repeat,
                })),
              (next) => {
                const current = itemById.get(item.id);
                if (!current) {
                  setDraftItemMeta(null);
                  setItemMenuId(null);
                  return;
                }
                const nextDueDate =
                  next?.dueDate ??
                  draftItemMeta?.dueDate ??
                  item.dueDate;
                const nextRepeat = normalizeRepeat(
                  next?.repeat ??
                  draftItemMeta?.repeat ??
                  item.repeat,
                );
                if (
                  current.dueDate !== nextDueDate ||
                  !repeatEqual(current.repeat, nextRepeat)
                ) {
                  activeListRef.current = listIdx;
                  dispatch(
                    updateTodoMeta(item.id, {
                      dueDate: nextDueDate,
                      repeat: nextRepeat,
                    }),
                  );
                }
                setDraftItemMeta(null);
                setItemMenuId(null);
              },
            )}
            {customLists.length > 0 && (
              <div className="menu-row" style={{ marginTop: "4px", paddingTop: "8px", borderTop: "1px solid rgba(0,0,0,0.08)" }}>
                <span>List</span>
                <select
                  value={item.listId ?? ""}
                  onChange={(e) => {
                    const newListId = e.target.value || undefined;
                    dispatch(moveTodo(item.id, newListId));
                    commitDraftItemMeta();
                    setItemMenuId(null);
                    setPopoverAnchor(null);
                  }}
                  style={{
                    border: "1px solid rgba(0,0,0,0.12)",
                    borderRadius: "6px",
                    padding: "4px 8px",
                    fontSize: "12px",
                    background: "#fff",
                    color: "#3c3c3c",
                    cursor: "pointer",
                  }}
                >
                  <option value="">Inbox</option>
                  {customLists.map((cl) => (
                    <option key={cl.id} value={cl.id}>
                      {cl.name}
                    </option>
                  ))}
                </select>
              </div>
            )}
          </div>,
          document.body,
        );
        })()}

        {completeMenuId === item.id && completeMenuAnchor && (() => {
          const estimatedCompleteHeight = 80;
          const spaceBelow = window.innerHeight - completeMenuAnchor.bottom - 8;
          const completeUp = spaceBelow < estimatedCompleteHeight && completeMenuAnchor.top > spaceBelow;
          return ReactDOM.createPortal(
          <div
            className={`TodoPlus-portal complete-menu${completeUp ? " up" : " down"}`}
            style={completeUp
              ? { position: "fixed", bottom: `${window.innerHeight - completeMenuAnchor.top + 8}px`, left: `${completeMenuAnchor.left}px` }
              : { position: "fixed", top: `${completeMenuAnchor.bottom + 8}px`, left: `${completeMenuAnchor.left}px` }
            }
          >
            <button
              onClick={() => {
                activeListRef.current = listIdx;
                if (!item.repeat) {
                  setCompleteMenuId(null);
                  return;
                }
                const currentDueDate = item.dueDate ?? getRepeatDerivedDueDate(item.repeat);
                // Collect dates that already have completed sibling instances
                const siblingDates = new Set(
                  items
                    .filter((i) => i.parentId === item.id && i.completed && i.dueDate)
                    .map((i) => i.dueDate!),
                );
                // Advance past dates that already have a completed instance
                let next = nextRepeatDate(
                  item.repeat,
                  currentDueDate,
                  today,
                );
                let safety = 0;
                while (next && siblingDates.has(getYmd(next)) && safety < 365) {
                  next = nextRepeatDate(item.repeat, getYmd(next), today);
                  safety += 1;
                }
                if (next) {
                  dispatch(
                    completeRepeatInstance(
                      item.id,
                      currentDueDate,
                      getYmd(next),
                    ),
                  );
                }
                setCompleteMenuId(null);
              }}
            >
              Completed This Instance
            </button>
            <button
              onClick={() => {
                activeListRef.current = listIdx;
                dispatch(toggleTodo(item.id));
                setCompleteMenuId(null);
              }}
            >
              Complete Task
            </button>
          </div>,
          document.body,
        );
        })()}

        <button
          className="delete"
          aria-label="Delete task"
          onClick={() => {
            activeListRef.current = listIdx;
            dispatch(removeTodo(item.id));
          }}
        >
          <RemoveIcon />
        </button>
        </div>
      );
    });

  // Panel-level elevation (z-index)
  const duePanelOpen =
    dueViewMenuOpen || dueListMenuOpen;
  const remainingPanelOpen =
    menuOpen || remainingMenuOpen || listPickerOpen || inboxViewMenuOpen;

  useEffect(() => {
    const recalc = () => {
      if (
        !rootRef.current ||
        !duePanelRef.current ||
        !dueListRef.current ||
        !remainingPanelRef.current ||
        !remainingListRef.current
      ) {
        return;
      }

      const viewportHeight = window.innerHeight;
      const verticalPadding = Math.max(40, Math.round(viewportHeight * 0.12));
      const availableHeight = Math.max(0, viewportHeight - verticalPadding);

      // Collect all panels
      type PanelInfo = { key: string; fixed: number; need: number };
      const panels: PanelInfo[] = [];

      panels.push({
        key: "due",
        fixed: duePanelRef.current.offsetHeight - dueListRef.current.offsetHeight,
        need: dueOpen ? dueListRef.current.scrollHeight : 0,
      });

      panels.push({
        key: "remaining",
        fixed: remainingPanelRef.current.offsetHeight - remainingListRef.current.offsetHeight,
        need: remainingOpen ? remainingListRef.current.scrollHeight : 0,
      });

      const rootStyles = getComputedStyle(rootRef.current);
      const gapFromCss = Number.parseFloat(rootStyles.rowGap || rootStyles.gap || "0");
      const panelGap = Number.isFinite(gapFromCss) && gapFromCss > 0
        ? gapFromCss
        : Math.max(8, Math.round(viewportHeight * 0.012));

      const totalFixed = panels.reduce((sum, p) => sum + p.fixed, 0);
      const free = Math.max(
        0,
        availableHeight - totalFixed - panelGap * Math.max(0, panels.length - 1),
      );

      // Proportional allocation with surplus redistribution
      const caps: Record<string, number> = {};
      const openPanels = panels.filter((p) => p.need > 0);
      const totalNeed = openPanels.reduce((sum, p) => sum + p.need, 0);

      if (totalNeed <= free) {
        panels.forEach((p) => { caps[p.key] = p.need; });
      } else if (totalNeed > 0) {
        const sorted = [...openPanels].sort((a, b) => a.need - b.need);
        let remainingFree = free;
        let remainingCount = sorted.length;
        for (const p of sorted) {
          const share = Math.floor(remainingFree / remainingCount);
          if (p.need <= share) {
            caps[p.key] = p.need;
            remainingFree -= p.need;
          } else {
            caps[p.key] = share;
            remainingFree -= share;
          }
          remainingCount -= 1;
        }
        panels.filter((p) => p.need === 0).forEach((p) => { caps[p.key] = 0; });
      } else {
        panels.forEach((p) => { caps[p.key] = 0; });
      }

      const newCappedLists: Record<string, boolean> = {};
      panels.forEach((p) => {
        newCappedLists[p.key] = p.need > (caps[p.key] ?? 0);
      });

      setListCaps((prev) => {
        const changed = panels.some((p) => prev[p.key] !== caps[p.key]);
        return changed ? caps : prev;
      });
      setCappedLists(newCappedLists);
    };

    recalc();

    const observer = new ResizeObserver(recalc);
    const elementsToObserve: (Element | null)[] = [
      rootRef.current,
      duePanelRef.current,
      dueListRef.current,
      remainingPanelRef.current,
      remainingListRef.current,
    ];
    elementsToObserve.forEach((el) => {
      if (el) observer.observe(el);
    });

    const handleResize = () => { recalc(); };
    window.addEventListener("resize", handleResize);
    return () => {
      observer.disconnect();
      window.removeEventListener("resize", handleResize);
    };
  }, [
    dueOpen,
    remainingOpen,
    dueView,
    inboxView,
    dueList.length,
    inboxList.length,
    menuOpen,
    duePanelOpen,
    remainingPanelOpen,
  ]);

  return (
    <div className="TodoPlus" ref={rootRef}>
      <div
        className={`panel${duePanelOpen ? " panel-open" : ""}${!dueOpen ? " panel-collapsed" : ""}`}
        ref={duePanelRef}
      >
        <div className="header">
          <div className="section-title">
            <div className="section-left">
              {addingListPanel === "due" ? (
                <div className="inline-rename">
                  <input
                    type="text"
                    placeholder="New list name"
                    value={newListName}
                    onChange={(e) => setNewListName(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter") commitAddList();
                      if (e.key === "Escape") { setAddingListPanel(null); setNewListName(""); }
                    }}
                    onBlur={() => { if (newListName.trim()) commitAddList(); else { setAddingListPanel(null); setNewListName(""); } }}
                    autoFocus
                  />
                </div>
              ) : renamingListId && renamingListId === dueView ? (
                <div className="inline-rename">
                  <input
                    type="text"
                    value={renameValue}
                    onChange={(e) => setRenameValue(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter") commitRename();
                      if (e.key === "Escape") { setRenamingListId(null); setRenameValue(""); }
                    }}
                    onBlur={commitRename}
                    autoFocus
                  />
                </div>
              ) : (
                <button
                  className="section-switch"
                  onClick={() => {
                    closeAllMenus();
                    setDueViewMenuOpen(true);
                  }}
                  aria-label="Choose list view"
                >
                  <span className="section-label">{dueLabel}</span>
                </button>
              )}
              <button
                className="section-collapse"
                onClick={() => setDueOpen(!dueOpen)}
                aria-label="Collapse list"
              >
                <Icon name={dueOpen ? "chevron-down" : "chevron-right"} />
              </button>
            </div>
            <button
              className="section-menu"
              onClick={() => {
                closeAllMenus();
                setDueListMenuOpen(true);
              }}
              aria-label="List options"
            >
              <Icon name="more-horizontal" />
            </button>
          </div>
        </div>
        {dueViewMenuOpen && (
          <div className="due-view-menu">
            <button
              onClick={() => {
                setDueView("today");
                closeAllMenus();
              }}
            >
              Due Today
            </button>
            <button
              onClick={() => {
                setDueView("finished");
                closeAllMenus();
              }}
            >
              Finished Tasks
            </button>
            {customLists.map((cl) => (
              <button
                key={cl.id}
                onClick={() => {
                  setDueView(cl.id);
                  closeAllMenus();
                }}
              >
                {cl.name}
              </button>
            ))}
          </div>
        )}
        {dueListMenuOpen && (
          <div className="list-menu">
            <button
              onClick={() => {
                closeAllMenus();
                toggleSettings();
              }}
            >
              Settings
            </button>
            <button
              onClick={() => {
                activeListRef.current = 0;
                removeCompleted(dueList, dueView === "finished");
                closeAllMenus();
              }}
            >
              Remove Finished Items
            </button>
            <button onClick={() => startAddList("due")}>
              Add List
            </button>
            {dueView !== "today" && dueView !== "finished" && (
              <>
                <button onClick={() => {
                  const list = customLists.find((l) => l.id === dueView);
                  if (list) startRenameList(list);
                }}>
                  Rename List
                </button>
                <button onClick={() => {
                  closeAllMenus();
                  deleteList(dueView);
                }}>
                  Delete List
                </button>
              </>
            )}
          </div>
        )}
        <div
          className="list"
          ref={dueListRef}
          style={{
            maxHeight: dueOpen ? `${listCaps.due}px` : "0px",
            overflowY: dueOpen ? "auto" : "hidden",
          }}
        >
          {dueOpen && (
            <>
              {dueList.length ? (
                renderItems(dueList, 0, {
                  showDue: true,
                  showRepeat: true,
                })
              ) : (
                <div className="empty">
                  {dueView === "today" ? "No tasks due today" : dueView === "finished" ? "No finished tasks" : `No tasks in ${dueLabel}`}
                </div>
              )}
            </>
          )}
        </div>

      </div>

      <div
        className={`panel${remainingPanelOpen ? " panel-open" : ""}${!remainingOpen ? " panel-collapsed" : ""}`}
        ref={remainingPanelRef}
      >
        <div className="header">
          <div className="section-title">
            <div className="section-left">
              {addingListPanel === "inbox" ? (
                <div className="inline-rename">
                  <input
                    type="text"
                    placeholder="New list name"
                    value={newListName}
                    onChange={(e) => setNewListName(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter") commitAddList();
                      if (e.key === "Escape") { setAddingListPanel(null); setNewListName(""); }
                    }}
                    onBlur={() => { if (newListName.trim()) commitAddList(); else { setAddingListPanel(null); setNewListName(""); } }}
                    autoFocus
                  />
                </div>
              ) : renamingListId && renamingListId === inboxView ? (
                <div className="inline-rename">
                  <input
                    type="text"
                    value={renameValue}
                    onChange={(e) => setRenameValue(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter") commitRename();
                      if (e.key === "Escape") { setRenamingListId(null); setRenameValue(""); }
                    }}
                    onBlur={commitRename}
                    autoFocus
                  />
                </div>
              ) : (
                <button
                  className="section-switch"
                  onClick={() => {
                    closeAllMenus();
                    setInboxViewMenuOpen(true);
                  }}
                  aria-label="Choose list view"
                >
                  <span className="section-label">{inboxLabel}</span>
                </button>
              )}
              <button
                className="section-collapse"
                onClick={() => setRemainingOpen(!remainingOpen)}
                aria-label="Collapse list"
              >
                <Icon name={remainingOpen ? "chevron-down" : "chevron-right"} />
              </button>
            </div>
            <button
              className="section-menu"
              onClick={() => {
                closeAllMenus();
                setRemainingMenuOpen(true);
              }}
              aria-label="List options"
            >
              <Icon name="more-horizontal" />
            </button>
          </div>
        </div>
        {inboxViewMenuOpen && (
          <div className="inbox-view-menu">
            <button
              onClick={() => {
                setInboxView("inbox");
                closeAllMenus();
              }}
            >
              Inbox
            </button>
            {customLists.map((cl) => (
              <button
                key={cl.id}
                onClick={() => {
                  setInboxView(cl.id);
                  closeAllMenus();
                }}
              >
                {cl.name}
              </button>
            ))}
          </div>
        )}
        {remainingMenuOpen && (
          <div className="list-menu">
            <button
              onClick={() => {
                closeAllMenus();
                toggleSettings();
              }}
            >
              Settings
            </button>
            <button
              onClick={() => {
                activeListRef.current = 1;
                removeCompleted(inboxList);
                closeAllMenus();
              }}
            >
              Remove Finished Items
            </button>
            <button onClick={() => startAddList("inbox")}>
              Add List
            </button>
            {inboxView !== "inbox" && (
              <>
                <button onClick={() => {
                  const list = customLists.find((l) => l.id === inboxView);
                  if (list) startRenameList(list);
                }}>
                  Rename List
                </button>
                <button onClick={() => {
                  closeAllMenus();
                  deleteList(inboxView);
                }}>
                  Delete List
                </button>
              </>
            )}
          </div>
        )}
        <div
          className="list"
          ref={remainingListRef}
          style={{
            maxHeight: remainingOpen ? `${listCaps.remaining}px` : "0px",
            overflowY: remainingOpen ? "auto" : "hidden",
          }}
        >
          {remainingOpen && (
            <>
              {inboxList.length ? (
                renderItems(inboxList, 1, { showDue: true, showRepeat: true })
              ) : (
                <div className="empty">
                  {inboxView === "inbox" ? "No remaining tasks" : `No tasks in ${inboxLabel}`}
                </div>
              )}
            </>
          )}
        </div>

        <div className="footer">
          <div className="composer">
            <input
              placeholder="New Task"
              value={input}
              onChange={(event) => setInput(event.target.value)}
              onFocus={() => setInputFocused(true)}
              onBlur={() => setInputFocused(false)}
              onKeyDown={(event) => {
                if (event.key === "Enter") {
                  event.preventDefault();
                  handleAdd();
                }
              }}
            />

            {customLists.length > 0 && (
              <div className="list-picker">
                <button
                  className={`list-picker-toggle${showMenuToggle ? "" : " hidden-control"}`}
                  onClick={() => {
                    closeAllMenus();
                    setListPickerOpen(!listPickerOpen);
                  }}
                  tabIndex={showMenuToggle ? 0 : -1}
                >
                  {selectedListId
                    ? customLists.find((l) => l.id === selectedListId)?.name ?? "Inbox"
                    : "Inbox"}
                  <Icon name="chevron-down" size={12} />
                </button>
                {listPickerOpen && (
                  <div className="list-picker-menu">
                    <button
                      className={!selectedListId ? "active" : ""}
                      onClick={() => {
                        setSelectedListId(undefined);
                        setListPickerOpen(false);
                      }}
                    >
                      Inbox
                    </button>
                    {customLists.map((cl) => (
                      <button
                        key={cl.id}
                        className={selectedListId === cl.id ? "active" : ""}
                        onClick={() => {
                          setSelectedListId(cl.id);
                          setListPickerOpen(false);
                        }}
                      >
                        {cl.name}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}

            <button
              className={`due-today${showMenuToggle ? "" : " hidden-control"}`}
              onClick={() => handleAddWithDueDate(getYmd(new Date()))}
              aria-label="Set due today"
              tabIndex={showMenuToggle ? 0 : -1}
            >
              Due Today
            </button>
            <button
              className={`menu-toggle${menuOpen ? " open" : ""}${showMenuToggle ? "" : " hidden-control"}`}
              onClick={() => {
                closeAllMenus();
                setMenuOpen(true);
              }}
              aria-label="Task options"
              tabIndex={showMenuToggle ? 0 : -1}
            >
              <Icon name="more-horizontal" />
            </button>
          </div>

          {menuOpen &&
            renderRepeatMenu(
              repeatType === "none"
                ? undefined
                : repeatType === "daily"
                  ? { type: "daily" }
                  : repeatType === "weekly"
                    ? { type: "weekly", days: customDays }
                    : { type: "custom", days: customDays },
              (next) => {
                if (!next) {
                  setRepeatType("none");
                  setCustomDays([]);
                } else if (next.type === "daily") {
                  setRepeatType("daily");
                  setCustomDays([]);
                } else if (next.type === "weekly") {
                  setRepeatType("weekly");
                  setCustomDays(next.days ?? []);
                } else {
                  setRepeatType("custom");
                  setCustomDays(next.days);
                }
              },
              dueDate,
              (next) => setDueDate(next),
              (next) => {
                const submitted = submitTaskWithMeta(next);
                if (!submitted && next?.dueDate) {
                  setDueDate(next.dueDate);
                }
                // Close menus without re-submitting (submitTaskWithMeta already handled it)
                setMenuOpen(false);
                setRemainingMenuOpen(false);
                setDueListMenuOpen(false);
                setDueViewMenuOpen(false);
                setCompleteMenuId(null);
                setItemMenuId(null);
              },
            )}
        </div>
      </div>

    </div>
  );
};

export default TodoPlus;
